@startuml

interface Monster {
  {abstract} announce()
  {abstract} move()
}

interface Bokoblin {
  {abstract} bludgeon()
  {abstract} defend()
}

interface Moblin {
  {abstract} stab()
  {abstract} kick()
}

interface Dungeon {
  {abstract} newBokoblin() : Bokoblin
  {abstract} newMoblin() : Moblin
}

class BlueBokoblin {
  + announce()
  + move()
  + bludgeon()
  + defend()
}

class BlueMoblin {
  + announce()
  + move()
  + stab()
  + kick()
}

class NormalBokoblin {
  + announce()
  + move()
  + bludgeon()
  + defend()
}

class NormalMoblin {
  + announce()
  + move()
  + stab()
  + kick()
}

class MediumDungeon {
  + newBokoblin() : Bokoblin
  + newMoblin() : Moblin
}

class EasyDungeon {
  + newBokoblin() : Bokoblin
  + newMoblin() : Moblin
}

class Encounter {
  - enemies : [Monster]
  - dungeon : Dungeon
  + announceEnemies()
  + moveEnemies()
}

Bokoblin --|> Monster
Moblin --|> Monster

BlueBokoblin ..|> Bokoblin
NormalBokoblin ..|> Bokoblin

BlueMoblin ..|> Moblin
NormalMoblin ..|> Moblin

MediumDungeon ..|> Dungeon
EasyDungeon ..|> Dungeon

MediumDungeon ..> BlueBokoblin
MediumDungeon ..> BlueMoblin

EasyDungeon ..> NormalBokoblin
EasyDungeon ..> NormalMoblin

Dungeon ..> Bokoblin
Dungeon ..> Moblin

Encounter --> Dungeon
Encounter --> Monster

@enduml
